msg.options = [];
for (let i = 0; i < msg.payload.length; i++) {
    msg.options[i] = msg.payload[i].nombre_completo;
}
delete msg.payload;
return msg;

msg.payload = {
    action: "open",
    t: Date.now() // Esto hace que el mensaje sea único cada vez
};
return msg;

// 1. Guardamos la contraseña escrita en la memoria segura del flujo
var passLimpia = msg.payload.toString().trim();
flow.set("PassEscrita", passLimpia);

// 2. Pedimos todos los usuarios a la base de datos
msg.payload = {
    query: "SELECT * FROM usuarios_login;"
};

return msg;

var tabla_usuarios = msg.payload;
var mi_nombre = flow.get("Nombre");
var mi_pass = flow.get("PassEscrita");

if (mi_nombre) mi_nombre = mi_nombre.toString().trim();
if (mi_pass) mi_pass = mi_pass.toString().trim();

var login_ok = false;

if (tabla_usuarios && tabla_usuarios.length > 0) {
    for (var i = 0; i < tabla_usuarios.length; i++) {
        var db_nom = tabla_usuarios[i].nombre_completo.toString().trim();
        var db_pass = tabla_usuarios[i].password.toString().trim();

        if (db_nom === mi_nombre && db_pass === mi_pass) {
            login_ok = true;
            // Guardamos los datos en el flow (como ya tenías)
            flow.set("DatosUsuario", tabla_usuarios[i]);

            // ¡NUEVO!: Guardamos el usuario (ej: "FHC3") en la variable global para el fichaje
            global.set("usuario_activo", tabla_usuarios[i].usuario);

            break;
        }
    }
}

if (login_ok) {
    node.warn("✅ Acceso correcto: " + mi_nombre);
    msg.payload = " "; // Va por la ruta 1 (Éxito)
} else {
    node.warn("❌ Acceso fallido: " + mi_nombre);
    msg.payload = ""; // Va por la ruta 2 (Error)
}

return msg;

// El payload debe ser exactamente el nombre de la pestaña (Tab) de destino
msg.payload = "Inicio";

// También puedes usar el índice (empezando desde 0)
// msg.payload = 0; // Esto iría a la primera pestaña

return msg;

if (msg.topic === "fecha") {
    let d = new Date(msg.payload);
    flow.set("filtro_fecha", d.toISOString().split('T')[0]);
}
if (msg.topic === "usuario") {
    flow.set("filtro_usuario", msg.payload);
}
let f = flow.get("filtro_fecha");
let u = flow.get("filtro_usuario");
if (f && u) {
    msg.params = [f, u];
    return msg;
}
return null;

let filas = msg.payload;
let sumaTotal = 0;

if (Array.isArray(filas)) {
    filas.forEach(f => {
        sumaTotal += parseInt(f["Cantidad"] || 0);
    });

    filas.push({
        "Tipo de Pieza": "TOTAL GENERAL",
        "Cantidad": sumaTotal
    });
}

msg.columns = [
    {
        "title": "TIPO DE PIEZA",
        "field": "Tipo de Pieza",
        "widthGrow": 7,
        "hozAlign": "center",
        "headerHozAlign": "center"
    },
    {
        "title": "CANTIDAD",
        "field": "Cantidad",
        "widthGrow": 3,
        "hozAlign": "center",
        "headerHozAlign": "center"
    }
];

msg.payload = filas;
return msg;

let filas = msg.payload;

// 1. Limpiamos la gráfica anterior para que no se amontonen las búsquedas
node.send({ payload: [] });

// 2. Mandamos las porciones de la tarta una a una
if (Array.isArray(filas)) {
    filas.forEach(fila => {
        let nombre = fila["Tipo de Pieza"];
        let valor = parseInt(fila["Cantidad"]);

        // Filtramos para ignorar el TOTAL y valores vacíos
        if (nombre && !nombre.includes("TOTAL") && valor > 0) {
            node.send({
                topic: nombre,
                payload: valor
            });
        }
    });
}

// Retornamos null porque ya hemos mandado los datos con node.send()
return null;

let lista = msg.payload;
// 1. Añadimos la opción global al principio de la lista
let opciones = ["Producción total"]; 

// 2. Extraemos los usuarios de la base de datos y los añadimos después
if (Array.isArray(lista)) {
    for (let i = 0; i < lista.length; i++) {
        if (lista[i].usuario) {
            opciones.push(lista[i].usuario);
        }
    }
}

msg.options = opciones;
msg.payload = ""; 
return msg;

// El payload debe ser exactamente el nombre de la pestaña (Tab) de destino
msg.payload = "Historial";

// También puedes usar el índice (empezando desde 0)
// msg.payload = 0; // Esto iría a la primera pestaña

return msg;
